mapper.update:
UPDATE sys_user
password = #{password}, name = #{name}, phone = #{phone}, address = #{address}, skill = #{skill}, avatar = #{avatar}, status = #{status}, reject_reason = #{rejectReason},
WHERE id = #{id}

mapper.select:
SELECT u.id, u.name, u.phone, u.skill, u.avatar, u.status, u.register_type AS registerType, (SELECT COUNT(*) FROM repair_order r WHERE r.worker_id = u.id AND r.status = 'completed') AS workCount, (SELECT AVG(e.score) FROM evaluation e INNER JOIN repair_order ro ON e.repair_id = ro.id WHERE ro.worker_id = u.id AND ro.status = 'completed') AS avgScore FROM sys_user u WHERE u.role = 'worker'
AND u.name LIKE CONCAT('%', #{name}, '%')
AND u.phone LIKE CONCAT('%', #{phone}, '%')
AND u.status = #{status}
ORDER BY u.create_time DESC LIMIT #{offset}, #{pageSize}
